      setState(() {
        _errorMessage = 'Invalid username or password';
        _isLoading = false;
      });
    }
  }

  Future<void> _saveAuthenticationStatus(bool status) async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setBool('isAuthenticated', status);
