      return 'Fingerprint';
    } else if (_availableBiometrics.contains(BiometricType.iris)) {
      return 'Iris';
    } else if (_availableBiometrics.contains(BiometricType.strong) || 
               _availableBiometrics.contains(BiometricType.weak)) {
      return 'Biometric';
    } else {
      return 'Biometric';
    }
  }

